/**
 * Утиліта для навігації з урахуванням ролі користувача
 */

/**
 * Перенаправлення користувача на домашню сторінку відповідно до його ролі
 * @param {Function} navigate - Функція navigate з React Router
 */
export const navigateToHome = async navigate => {
  try {
    const userId = localStorage.getItem('user_id');
    if (!userId) {
      navigate('/');
      return;
    }

    // Перевіряємо роль користувача
    const response = await fetch(`http://localhost:5000/api/user-role/${userId}`);
    if (!response.ok) {
      throw new Error('Помилка при перевірці ролі користувача');
    }
    const userData = await response.json();

    // Перенаправлення на відповідну панель
    if (userData.role === 'admin') {
      navigate('/admin-dashboard');
    } else {
      navigate('/dashboard');
    }
  } catch (error) {
    console.error('Помилка при навігації:', error);
    // У випадку помилки перенаправляємо на звичайну панель
    navigate('/dashboard');
  }
};

